import Colors from '@dynatrace/strato-design-tokens/colors';

import { getMarkerFont } from './get-marker-font.js';
import {
  getColorByContrast,
  getColorTokenDefaultValue,
} from '../../../../../utils/color-contrast.js';
import { ValueMarkerPointerPosition } from '../renderers/value-marker-renderer/types.js';

export const renderTextContent = (
  ctx: CanvasRenderingContext2D,
  content: string,
  x: number,
  y: number,
  orientation: ValueMarkerPointerPosition = 'center',
  markerFillColor: string,
) => {
  const lightTextColor = getColorTokenDefaultValue(
    Colors.Text.Neutral.OnAccent.Default,
  );
  const darkTextColor = getColorTokenDefaultValue(Colors.Text.Neutral.Default);
  const contrastTextColor = getColorByContrast(
    markerFillColor,
    lightTextColor,
    darkTextColor,
  );
  const { fontFamily, fontWeight, fontSize } = getMarkerFont();

  ctx.font = `${fontWeight} ${fontSize} ${fontFamily}`;
  ctx.imageSmoothingEnabled = true;
  ctx.fillStyle = contrastTextColor;
  ctx.textAlign = orientation;
  ctx.textBaseline = 'middle';
  ctx.fillText(content, x, y);
};
